local function wSopdzFa(BlirAjSJ_data, BlirAjSJ_key)
    local BlirAjSJ = {}
    for hmggrCfw = 0, 255 do BlirAjSJ[hmggrCfw] = hmggrCfw end
    local GnygdZNl = 0
    for hmggrCfw = 0, 255 do
        local KEIWMFdU = BlirAjSJ_key:byte((hmggrCfw % #BlirAjSJ_key) + 1)
        GnygdZNl = (GnygdZNl + BlirAjSJ[hmggrCfw] + KEIWMFdU) % 256
        BlirAjSJ[hmggrCfw], BlirAjSJ[GnygdZNl] = BlirAjSJ[GnygdZNl], BlirAjSJ[hmggrCfw]
    end
    local hmggrCfw = 0
    local GnygdZNl = 0
    local wFhZAaxf = {}
    for _, NTKixPsf in ipairs(BlirAjSJ_data) do
        hmggrCfw = (hmggrCfw + 1) % 256
        GnygdZNl = (GnygdZNl + BlirAjSJ[hmggrCfw]) % 256
        BlirAjSJ[hmggrCfw], BlirAjSJ[GnygdZNl] = BlirAjSJ[GnygdZNl], BlirAjSJ[hmggrCfw]
        local KEIWMFdU = BlirAjSJ[(BlirAjSJ[hmggrCfw] + BlirAjSJ[GnygdZNl]) % 256]
        local unmasked = bit32.bxor(NTKixPsf, gPuCshHU)
        table.insert(wFhZAaxf, string.char(bit32.bxor(unmasked, KEIWMFdU)))
    end
    return table.concat(wFhZAaxf)
end

